def get_cached_by_id(id) do
  key = "id:#{id}"

  ap_id =
    @cachex.fetch!(:user_cache, key, fn _ ->
      user = get_by_id(id)

      if user do
        @cachex.put(:user_cache, "ap_id:#{user.ap_id}", user)
        {:commit, user.ap_id}
      else
        {:ignore, ""}
      end
    end)

  get_cached_by_ap_id(ap_id)
end

def paginate(query, page, page_size) do
  from(u in query, limit: ^page_size, offset: ^((page - 1) * page_size))
end

def key_id_to_user_id(key_id) do
  from(sk in __MODULE__, where: sk.key_id == ^key_id) |> select([sk], sk.user_id) |> Repo.one()
end

def public_key_pem(%User{} = user) do
  case Repo.preload(user, :signing_key) do
    %User{signing_key: %__MODULE__{public_key: public_key_pem}} -> {:ok, public_key_pem}
    _ -> {:error, "key not found"}
  end
end
def public_key_pem(_e) do
  {:error, "key not found"}
end

def tombstone(actor, id) do
  {:ok, %{"id" => id, "actor" => actor, "type" => "Tombstone"}, []}
end

